import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read the entire line

        // Implement input validation to limit the length of input
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum allowed length of 10 characters. Exiting.");
            return;
        }

        // Copy user input into a buffer with proper boundary checks
        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), 10), buffer, 0); // Ensure not to copy more than buffer size

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra spaces in the output
    }
}

